import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
} from 'recharts';

function SignalChart({ data, tOn, tOff }) {
  const WINDOW_SIZE = 100; // 10 seconds at 100ms per point

  // Compute dynamic Y max
  let yMax = 3.0;
  if (data.length > 0) {
    const maxVal = Math.max(...data.map((d) => d.y));
    yMax = Math.max(maxVal * 1.2, tOn * 1.5, 2.0);
  }

  // Sliding window: X domain follows the latest point
  const xMax = data.length > 0 ? data[data.length - 1].x : WINDOW_SIZE - 1;
  const xMin = xMax - WINDOW_SIZE + 1;

  return (
    <div className="card signal-card">
      <h3>Activation Signal</h3>
      <ResponsiveContainer width="100%" height={180}>
        <LineChart data={data} margin={{ top: 5, right: 10, left: 0, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#e8e8ec" />
          <XAxis
            dataKey="x"
            domain={[xMin, xMax]}
            tick={false}
            axisLine={{ stroke: '#ddd' }}
            type="number"
          />
          <YAxis
            domain={[0, yMax]}
            tick={{ fill: '#999', fontSize: 11 }}
            axisLine={{ stroke: '#ddd' }}
            width={40}
          />
          <Tooltip
            contentStyle={{
              background: '#fff',
              border: '1px solid #e0e0e0',
              borderRadius: 8,
              fontSize: 12,
              fontFamily: 'inherit',
              boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
            }}
            labelStyle={{ color: '#999' }}
            formatter={(value) => [value.toFixed(3), 'Activation']}
          />
          <ReferenceLine
            y={tOn}
            stroke="#e05555"
            strokeDasharray="6 3"
            strokeWidth={1.2}
            label={{ value: `T_ON=${tOn}`, fill: '#e05555', fontSize: 10, position: 'right' }}
          />
          <ReferenceLine
            y={tOff}
            stroke="#e0a030"
            strokeDasharray="6 3"
            strokeWidth={1}
            label={{ value: `T_OFF=${tOff}`, fill: '#e0a030', fontSize: 10, position: 'right' }}
          />
          <Line
            type="monotone"
            dataKey="y"
            stroke="#5b6abf"
            strokeWidth={1.8}
            dot={false}
            isAnimationActive={false}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

export default SignalChart;
